package org.apache.commons.csv;

import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import java.io.IOException;
import java.io.InputStream;
import java.net.URL;
import java.nio.charset.Charset;

import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;

class CSVParserTest {

    private URL mockUrl;
    private InputStream mockInputStream;
    private Charset charset;
    private CSVFormat format;

    @BeforeEach
    void setUp() throws IOException {
        mockUrl = mock(URL.class);
        mockInputStream = mock(InputStream.class);
        charset = Charset.forName("UTF-8");
        format = mock(CSVFormat.class);

        when(mockUrl.openStream()).thenReturn(mockInputStream);
    }

    @Test
    void testParse_NullUrl_ThrowsException() {
        NullPointerException thrown = assertThrows(NullPointerException.class,
                () -> CSVParser.class.getMethod("parse", URL.class, Charset.class, CSVFormat.class)
                        .invoke(null, (URL) null, charset, format));
        assertEquals("url", thrown.getCause().getMessage());
    }

    @Test
    void testParse_NullCharset_ThrowsException() {
        NullPointerException thrown = assertThrows(NullPointerException.class,
                () -> CSVParser.class.getMethod("parse", URL.class, Charset.class, CSVFormat.class)
                        .invoke(null, mockUrl, null, format));
        assertEquals("charset", thrown.getCause().getMessage());
    }

    @Test
    void testParse_NullFormat_ThrowsException() {
        NullPointerException thrown = assertThrows(NullPointerException.class,
                () -> CSVParser.class.getMethod("parse", URL.class, Charset.class, CSVFormat.class)
                        .invoke(null, mockUrl, charset, null));
        assertEquals("format", thrown.getCause().getMessage());
    }

    @Test
    void testParse_Success() throws Exception {
        CSVParser parser = CSVParser.class
                .getMethod("parse", URL.class, Charset.class, CSVFormat.class)
                .invoke(null, mockUrl, charset, format);
        assertNotNull(parser);
    }
}
